import React, { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import Layout from '../../components/shared/Layout';
import axiosInstance from '../../utils/axiosInstance';

const Badge = ({ status }) => {
  const colors = { ACTIVE: '#22c55e', PENDING_VERIFICATION: '#f59e0b', REJECTED: '#ef4444' };
  const c = colors[status] || '#94a3b8';
  return <span style={{ padding: '3px 10px', borderRadius: 99, background: c + '20', color: c, fontWeight: 700, fontSize: 12 }}>{status}</span>;
};

export default function AdminCustomers() {
  const [customers, setCustomers] = useState([]);
  const [selected, setSelected] = useState(null);
  const [showDetail, setShowDetail] = useState(false);

  const fetchCustomers = () => axiosInstance.get('/customers').then(r => setCustomers(r.data.customers || []));

  useEffect(() => { fetchCustomers(); }, []);

  const approve = async (id) => {
    try { await axiosInstance.patch(`/customers/${id}/approve`); toast.success('KYC Approved!'); fetchCustomers(); setSelected(null); setShowDetail(false); }
    catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const reject = async (id) => {
    try { await axiosInstance.patch(`/customers/${id}/reject`); toast.success('KYC Rejected'); fetchCustomers(); setSelected(null); setShowDetail(false); }
    catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const selectCustomer = (c) => {
    setSelected(c);
    setShowDetail(true);
  };

  return (
    <Layout>
      <div className="pt-5 pt-md-0">
        <h2 className="mb-4" style={{ color: '#1e293b' }}>👥 Customers</h2>
      </div>

      <div className="row g-3 align-items-start">
        {/* Table column */}
        <div className={selected ? 'col-12 col-lg-7' : 'col-12'}>
          <div style={{ background: '#fff', borderRadius: 12, overflow: 'hidden', boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
            <div className="table-responsive">
              <table className="table table-hover mb-0" style={{ minWidth: 700 }}>
                <thead style={{ background: '#f8fafc' }}>
                  <tr>
                    {['Customer ID', 'Name', 'Email', 'Phone', 'Gov ID Type', 'Status', 'Joined', 'Actions'].map(h => (
                      <th key={h} style={{ padding: '12px 16px', fontSize: 12, fontWeight: 700, color: '#475569', borderBottom: '1px solid #e2e8f0' }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {customers.map(c => (
                    <tr key={c.customerId} onClick={() => selectCustomer(c)} style={{ borderBottom: '1px solid #f1f5f9', cursor: 'pointer', background: selected?.customerId === c.customerId ? '#eff6ff' : 'transparent' }}>
                      <td style={{ padding: '12px 16px', fontFamily: 'monospace', fontSize: 12, color: '#3b82f6' }}>{c.customerId}</td>
                      <td style={{ padding: '12px 16px', fontWeight: 600 }}>{c.name}</td>
                      <td style={{ padding: '12px 16px', fontSize: 13, color: '#64748b' }}>{c.email}</td>
                      <td style={{ padding: '12px 16px', fontSize: 13 }}>{c.phone}</td>
                      <td style={{ padding: '12px 16px', fontSize: 12 }}>{c.govIdType}</td>
                      <td style={{ padding: '12px 16px' }}><Badge status={c.status} /></td>
                      <td style={{ padding: '12px 16px', fontSize: 12, color: '#94a3b8' }}>{new Date(c.createdAt).toLocaleDateString('en-IN')}</td>
                      <td style={{ padding: '12px 16px' }}>
                        {c.status === 'PENDING_VERIFICATION' && (
                          <div className="d-flex gap-2 flex-wrap" onClick={e => e.stopPropagation()}>
                            <button onClick={() => approve(c.customerId)} className="btn btn-sm" style={{ padding: '4px 12px', borderRadius: 6, border: 'none', background: '#22c55e', color: '#fff', fontWeight: 700, fontSize: 12 }}>Approve</button>
                            <button onClick={() => reject(c.customerId)} className="btn btn-sm" style={{ padding: '4px 12px', borderRadius: 6, border: 'none', background: '#ef4444', color: '#fff', fontWeight: 700, fontSize: 12 }}>Reject</button>
                          </div>
                        )}
                      </td>
                    </tr>
                  ))}
                  {customers.length === 0 && <tr><td colSpan={8} className="text-center py-4" style={{ color: '#94a3b8' }}>No customers found</td></tr>}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* Detail panel */}
        {selected && (
          <div className="col-12 col-lg-5">
            <div style={{ background: '#fff', borderRadius: 12, padding: 24, boxShadow: '0 2px 8px rgba(0,0,0,0.06)', position: 'relative' }}>
              <button onClick={() => { setSelected(null); setShowDetail(false); }} style={{ position: 'absolute', top: 16, right: 16, background: 'none', border: 'none', fontSize: 20, cursor: 'pointer', color: '#94a3b8' }}>✕</button>
              <h3 className="mb-4">{selected.name}</h3>
              {[['Customer ID', selected.customerId], ['Email', selected.email], ['Phone', selected.phone], ['Address', selected.address], ['Gov ID Type', selected.govIdType], ['Gov ID Number', selected.govIdNumber], ['Status', selected.status]].map(([lbl, val]) => (
                <div key={lbl} className="d-flex justify-content-between flex-wrap gap-1 py-2" style={{ borderBottom: '1px solid #f1f5f9', fontSize: 13 }}>
                  <span style={{ color: '#64748b' }}>{lbl}</span>
                  <span style={{ fontWeight: 600, wordBreak: 'break-all' }}>{val || '—'}</span>
                </div>
              ))}
              {selected.govIdDocumentPath && (
                <div className="mt-3">
                  <p style={{ fontSize: 13, fontWeight: 600, marginBottom: 8 }}>KYC Document</p>
                  <a href={`http://localhost:5000/${selected.govIdDocumentPath}`} style={{ color: '#3b82f6', fontSize: 13 }}>View Document →</a>
                </div>
              )}
              {selected.status === 'PENDING_VERIFICATION' && (
                <div className="d-flex gap-2 mt-4">
                  <button onClick={() => approve(selected.customerId)} className="btn flex-fill" style={{ padding: 12, borderRadius: 8, border: 'none', background: '#22c55e', color: '#fff', fontWeight: 700 }}>✅ Approve KYC</button>
                  <button onClick={() => reject(selected.customerId)} className="btn flex-fill" style={{ padding: 12, borderRadius: 8, border: 'none', background: '#ef4444', color: '#fff', fontWeight: 700 }}>❌ Reject KYC</button>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </Layout>
  );
}
